import { VALIDATION_MODE } from '../constants';
import type {
  FieldValues,
  FormState,
  InternalFieldName,
  ReadFormState,
} from '../types';
import isEmptyObject from '../utils/isEmptyObject';

export default <T extends FieldValues, K extends ReadFormState>(
  formStateData: Partial<FormState<T>> & {
    name?: InternalFieldName;
    values?: T;
  },
  _proxyFormState: K,
  updateFormState: (formState: Partial<FormState<T>>) => void,
  isRoot?: boolean,
) => {
  updateFormState(formStateData);
  const { name, ...formState } = formStateData;

  return (
    isEmptyObject(formState) ||
    (isRoot &&
      Object.keys(formState).length >= Object.keys(_proxyFormState).length) ||
    Object.keys(formState).find(
      (key) =>
        _proxyFormState[key as keyof ReadFormState] ===
        (!isRoot || VALIDATION_MODE.all),
    )
  );
};

import type { FieldError, FieldErrors, FieldValues } from '../types';
import get from '../utils/get';
import isKey from '../utils/isKey';

export default function schemaErrorLookup<T extends FieldValues = FieldValues>(
  errors: FieldErrors<T>,
  _fields: FieldValues,
  name: string,
): {
  error?: FieldError;
  name: string;
} {
  const error = get(errors, name);

  if (error || isKey(name)) {
    return {
      error,
      name,
    };
  }

  const names = name.split('.');

  while (names.length) {
    const fieldName = names.join('.');
    const field = get(_fields, fieldName);
    const foundError = get(errors, fieldName);

    if (field && !Array.isArray(field) && name !== fieldName) {
      return { name };
    }

    if (foundError && foundError.type) {
      return {
        name: fieldName,
        error: foundError,
      };
    }

    if (foundError && foundError.root && foundError.root.type) {
      return {
        name: `${fieldName}.root`,
        error: foundError.root,
      };
    }

    names.pop();
  }

  return {
    name,
  };
}

import {capitalizeString} from './capitalizeString'

import {Action, Props} from './index.types'

export function callOnChangeProps<
  S extends object,
  A extends {type: string},
  P extends Props<S, A>,
>(action: Action<S, A, P>, props: P, state: S, newState: S) {
  const {type} = action
  const changes: Partial<S> = {}
  const keys = Object.keys(state) as (keyof S)[]

  for (const key of keys) {
    invokeOnChangeHandler(key, action, props, state, newState)

    if (newState[key] !== state[key]) {
      changes[key] = newState[key]
    }
  }

  if (
    typeof props.onStateChange === 'function' &&
    Object.keys(changes).length
  ) {
    props.onStateChange({type, ...changes})
  }
}

function invokeOnChangeHandler<
  S extends object,
  A extends {type: string},
  P extends Props<S, A>,
>(key: keyof S, action: Action<S, A, P>, props: P, state: S, newState: S) {
  if (newState[key] === state[key]) {
    return
  }

  const handlerKey = `on${capitalizeString(key as string)}Change`
  const handler = (props as Record<string, unknown>)[handlerKey]

  if (typeof handler !== 'function') {
    return
  }

  const {type} = action

  handler({type, ...newState})
}

import type { PropertyTransform, TransformArgs } from "./types"

export const colorMix = (value: string, token: TransformArgs["token"]) => {
  if (!value || typeof value !== "string") {
    return { invalid: true, value }
  }

  const [rawColor, rawOpacity] = value.split("/")

  if (!rawColor || !rawOpacity || rawColor === "currentBg") {
    return { invalid: true, value: rawColor }
  }

  const colorToken = token(`colors.${rawColor}`)
  const opacityToken = token.raw(`opacity.${rawOpacity}`)?.value

  if (!opacityToken && isNaN(Number(rawOpacity))) {
    return { invalid: true, value: rawColor }
  }

  const percent = opacityToken
    ? Number(opacityToken) * 100 + "%"
    : `${rawOpacity}%`

  const color = colorToken ?? rawColor

  return {
    invalid: false,
    color,
    value: `color-mix(in srgb, ${color} ${percent}, transparent)`,
  }
}

export const createColorMixTransform =
  (prop: string): PropertyTransform =>
  (value, args) => {
    const mix = args.utils.colorMix(value)
    if (mix.invalid) return { [prop]: value }
    const cssVar = "--mix-" + prop
    return {
      [cssVar]: mix.value,
      [prop]: `var(${cssVar}, ${mix.color})`,
    }
  }

import { PROTOTYPE_KEYWORDS } from '../constants';

import isKey from './isKey';
import isNullOrUndefined from './isNullOrUndefined';
import isObject from './isObject';
import isUndefined from './isUndefined';
import stringToPath from './stringToPath';

export default <T>(
  object: T,
  path?: string | null,
  defaultValue?: unknown,
): any => {
  if (!path || !isObject(object)) {
    return defaultValue;
  }

  const paths = isKey(path) ? [path] : stringToPath(path);
  if (paths.some((key) => PROTOTYPE_KEYWORDS.includes(key))) {
    return defaultValue;
  }

  const result = paths.reduce<any>((result, key) => {
    return isNullOrUndefined(result) ? undefined : result[key];
  }, object);

  return isUndefined(result) || result === object
    ? isUndefined(object[path as keyof T])
      ? defaultValue
      : object[path as keyof T]
    : result;
};

import styledError from '../utils/error';

const MAX_SMI = 1 << 30;

let groupIDRegister: Map<string, number> = new Map();
let reverseRegister: Map<number, string> = new Map();
let nextFreeGroup = 1;

export const resetGroupIds = () => {
  groupIDRegister = new Map();
  reverseRegister = new Map();
  nextFreeGroup = 1;
};

export const groupForId = (id: string): number => {
  const existing = groupIDRegister.get(id);
  if (existing !== undefined) return existing;

  while (reverseRegister.has(nextFreeGroup)) {
    nextFreeGroup++;
  }

  const group = nextFreeGroup++;

  if (__DEV__ && ((group | 0) < 0 || group > MAX_SMI)) {
    throw styledError(16, `${group}`);
  }

  groupIDRegister.set(id, group);
  reverseRegister.set(group, id);
  return group;
};

export const idForGroup = (group: number): void | string => {
  return reverseRegister.get(group);
};

export const setGroupForId = (id: string, group: number) => {
  // move pointer
  nextFreeGroup = group + 1;

  groupIDRegister.set(id, group);
  reverseRegister.set(group, id);
};

import { ReorderPayload } from '../types';

export function reorderErrors<T>(path: unknown, { from, to }: ReorderPayload, errors: T): T {
  const oldKeyStart = `${path}.${from}`;
  const newKeyStart = `${path}.${to}`;

  const clone: any = { ...errors };
  const processedKeys = new Set<string>();

  Object.keys(errors as any).forEach((key) => {
    if (processedKeys.has(key)) {
      return;
    }

    let oldKey;
    let newKey;

    if (key.startsWith(oldKeyStart)) {
      oldKey = key;
      newKey = key.replace(oldKeyStart, newKeyStart);
    } else if (key.startsWith(newKeyStart)) {
      oldKey = key.replace(newKeyStart, oldKeyStart);
      newKey = key;
    }

    if (oldKey && newKey) {
      const value1 = clone[oldKey];
      const value2 = clone[newKey];

      value2 === undefined ? delete clone[oldKey] : (clone[oldKey] = value2);
      value1 === undefined ? delete clone[newKey] : (clone[newKey] = value1);

      processedKeys.add(oldKey);
      processedKeys.add(newKey);
    }
  });

  return clone;
}

import type { ChartData } from '../types';
import type { AreaChartSeries } from './AreaChart';

interface GetSplitOffsetInput {
  data: ChartData;
  dataKey: string;
}

export function getSplitOffset({ data, dataKey }: GetSplitOffsetInput) {
  const dataMax = Math.max(...data.map((item) => item[dataKey]));
  const dataMin = Math.min(...data.map((item) => item[dataKey]));

  if (dataMax <= 0) {
    return 0;
  }
  if (dataMin >= 0) {
    return 1;
  }

  return dataMax / (dataMax - dataMin);
}

interface GetDefaultSplitOffsetInput {
  data: ChartData;
  series: AreaChartSeries[];
}

export function getDefaultSplitOffset({ data, series }: GetDefaultSplitOffsetInput) {
  if (series.length === 1) {
    const dataKey = series[0].name;
    return getSplitOffset({ data, dataKey });
  }

  return 0.5;
}

export function getPreviousIndex(
  currentIndex: number,
  elements: NodeListOf<HTMLDivElement> | HTMLDivElement[],
  loop: boolean
) {
  for (let i = currentIndex - 1; i >= 0; i -= 1) {
    if (!elements[i].hasAttribute('data-combobox-disabled')) {
      return i;
    }
  }

  if (loop) {
    for (let i = elements.length - 1; i > -1; i -= 1) {
      if (!elements[i].hasAttribute('data-combobox-disabled')) {
        return i;
      }
    }
  }

  return currentIndex;
}

export function getNextIndex(
  currentIndex: number,
  elements: NodeListOf<HTMLDivElement> | HTMLDivElement[],
  loop: boolean
) {
  for (let i = currentIndex + 1; i < elements.length; i += 1) {
    if (!elements[i].hasAttribute('data-combobox-disabled')) {
      return i;
    }
  }

  if (loop) {
    for (let i = 0; i < elements.length; i += 1) {
      if (!elements[i].hasAttribute('data-combobox-disabled')) {
        return i;
      }
    }
  }

  return currentIndex;
}

export function getFirstIndex(elements: NodeListOf<HTMLDivElement> | HTMLDivElement[]) {
  for (let i = 0; i < elements.length; i += 1) {
    if (!elements[i].hasAttribute('data-combobox-disabled')) {
      return i;
    }
  }

  return -1;
}

import dayjs from 'dayjs';
import { DateStringValue } from '../../../types';
import { PickerControlProps } from '../../PickerControl';
import { isYearDisabled } from '../is-year-disabled/is-year-disabled';

interface GetYearInTabOrderInput {
  years: DateStringValue[][];
  minDate: DateStringValue | Date | undefined;
  maxDate: DateStringValue | Date | undefined;
  getYearControlProps: ((year: DateStringValue) => Partial<PickerControlProps>) | undefined;
}

export function getYearInTabOrder({
  years,
  minDate,
  maxDate,
  getYearControlProps,
}: GetYearInTabOrderInput) {
  const enabledYears = years
    .flat()
    .filter(
      (year) =>
        !isYearDisabled({ year, minDate, maxDate }) && !getYearControlProps?.(year)?.disabled
    );

  const selectedYear = enabledYears.find((year) => getYearControlProps?.(year)?.selected);

  if (selectedYear) {
    return selectedYear;
  }

  const currentYear = enabledYears.find((year) => dayjs().isSame(year, 'year'));

  if (currentYear) {
    return currentYear;
  }

  return enabledYears[0];
}

import { createContext, use } from 'react';
import { UseForm, UseFormReturnType } from '../types';
import { useForm } from '../use-form';

export interface FormProviderProps<Form> {
  form: Form;
  children: React.ReactNode;
}

export function createFormContext<Values, TransformedValues = Values, Rules = any>() {
  type Form = UseFormReturnType<Values, TransformedValues, Rules>;

  const FormContext = createContext<Form | null>(null);

  function FormProvider({ form, children }: FormProviderProps<Form>) {
    return <FormContext value={form}>{children}</FormContext>;
  }

  function useFormContext() {
    const ctx = use(FormContext);
    if (!ctx) {
      throw new Error('useFormContext was called outside of FormProvider context');
    }

    return ctx;
  }

  return [FormProvider, useFormContext, useForm] as [
    React.FC<FormProviderProps<Form>>,
    () => Form,
    UseForm<Values, TransformedValues, Rules>,
  ];
}

import dayjs from 'dayjs';
import { DateStringValue, DayOfWeek } from '../../../types';
import { getStartOfWeek } from '../../../utils';

interface GetWeeksInRangeInput {
  rangeStart: dayjs.Dayjs;
  rangeEnd: dayjs.Dayjs;
  firstDayOfWeek: DayOfWeek;
}

interface GetWeeksInRangeOutput {
  weeks: DateStringValue[][];
  groupedByDay: { [date: string]: any[] };
}

export function getWeeksInRange({
  rangeStart,
  rangeEnd,
  firstDayOfWeek,
}: GetWeeksInRangeInput): GetWeeksInRangeOutput {
  const weeks: DateStringValue[][] = [];
  const groupedByDay: { [date: string]: any[] } = {};

  const startOfFirstWeekStr = getStartOfWeek({
    date: rangeStart.format('YYYY-MM-DD'),
    firstDayOfWeek,
  });

  let currentDate = dayjs(startOfFirstWeekStr);

  while (currentDate.isBefore(rangeEnd) || currentDate.isSame(rangeEnd, 'day')) {
    const week: DateStringValue[] = [];
    for (let i = 0; i < 7; i++) {
      const dateStr = currentDate.format('YYYY-MM-DD 00:00:00');
      week.push(dateStr);
      if (!groupedByDay[dateStr]) {
        groupedByDay[dateStr] = [];
      }
      currentDate = currentDate.add(1, 'day');
    }
    weeks.push(week);
  }

  return { weeks, groupedByDay };
}

import dayjs from 'dayjs';
import type { ReactNode } from 'react';
import { DateLabelFormat, DateStringValue } from '../../../types';
import { formatDate } from '../../../utils';

interface GetWeekLabelInput {
  weekdays: Date[] | string[];
  locale: string;
  weekLabelFormat: DateLabelFormat;
  renderWeekLabel?: (params: { weekStart: DateStringValue; weekEnd: DateStringValue }) => ReactNode;
}

export function getWeekLabel({
  weekdays,
  locale,
  weekLabelFormat,
  renderWeekLabel,
}: GetWeekLabelInput) {
  if (renderWeekLabel) {
    return renderWeekLabel({
      weekStart: dayjs(weekdays[0]).format('YYYY-MM-DD'),
      weekEnd: dayjs(weekdays[weekdays.length - 1]).format('YYYY-MM-DD'),
    });
  }

  return `${formatDate({
    locale,
    date: weekdays[0],
    format: weekLabelFormat,
  })} – ${formatDate({
    locale,
    date: weekdays[weekdays.length - 1],
    format: weekLabelFormat,
  })}, ${formatDate({ locale, date: weekdays[0], format: 'YYYY' })}`;
}

import dayjs, { Dayjs } from 'dayjs';
import { DateStringValue } from '../../../types';

interface CalculateAllDayEventWidthInput {
  eventStartDate: Dayjs;
  actualEndDate: Dayjs;
  weekStartDate: Dayjs;
  weekEndDate: Dayjs;
  weekDays: DateStringValue[];
  visibleDaysCount: number;
}

export function calculateAllDayEventWidth({
  eventStartDate,
  actualEndDate,
  weekStartDate,
  weekEndDate,
  weekDays,
  visibleDaysCount,
}: CalculateAllDayEventWidthInput): number {
  let displayStartDate = eventStartDate;
  if (eventStartDate.isBefore(weekStartDate)) {
    displayStartDate = weekStartDate;
  }

  let displayEndDate = actualEndDate;
  if (actualEndDate.isAfter(weekEndDate)) {
    displayEndDate = weekEndDate;
  }

  const visibleDaysSpanned = weekDays.filter(
    (day) =>
      (dayjs(day).isAfter(displayStartDate) || dayjs(day).isSame(displayStartDate, 'day')) &&
      (dayjs(day).isBefore(displayEndDate) || dayjs(day).isSame(displayEndDate, 'day'))
  ).length;

  return (visibleDaysSpanned / visibleDaysCount) * 100;
}

import { DateStringValue, ScheduleEventData } from '../../../types';
import { isAllDayEvent, isEventsOverlap } from '../../../utils';

interface FindAvailableColumnInput {
  columns: Map<string, ScheduleEventData[]>;
  event: ScheduleEventData;
  allDay: boolean;
  allWeekDays: DateStringValue[];
}

function columnHasConflict({
  columns,
  columnIndex,
  event,
  allDay,
  allWeekDays,
}: FindAvailableColumnInput & { columnIndex: number }): boolean {
  const columnKey = `col-${columnIndex}`;
  if (!columns.has(columnKey)) {
    return false;
  }

  const columnEvents = columns.get(columnKey)!;

  return columnEvents.some((e) => {
    const eAllDay = allWeekDays.some((day) => isAllDayEvent({ event: e, date: day }));
    const hasTimeConflict = isEventsOverlap(e, event);

    if (allDay && eAllDay) {
      return hasTimeConflict;
    }

    if (allDay || eAllDay) {
      return false;
    }

    return hasTimeConflict;
  });
}

export function findAvailableColumn(input: FindAvailableColumnInput): number {
  let column = 0;

  while (columnHasConflict({ ...input, columnIndex: column })) {
    column++;
  }

  return column;
}
